    @staticmethod
    def lower(value: AgentProtocol):
        if not isinstance(value, Agent):
            raise TypeError("Expected Agent instance, {} found".format(type(value).__name__))
        return value._uniffi_clone_pointer()

    @classmethod
    def read(cls, buf: _UniffiRustBuffer):
        ptr = buf.read_u64()
        if ptr == 0:
            raise InternalError("Raw pointer value was null")
        return cls.lift(ptr)

