def album_hash(album: "str",album_artist: "str") -> "str":
    _UniffiConverterString.check_lower(album)
    
    _UniffiConverterString.check_lower(album_artist)
    
    return _UniffiConverterString.lift(_uniffi_rust_call(_UniffiLib.uniffi_rocksky_uniffi_fn_func_album_hash,
        _UniffiConverterString.lower(album),
        _UniffiConverterString.lower(album_artist)))


